import UIKit

@UIApplicationMain
class AppDelegate: UIResponder, UIApplicationDelegate {

    var window: UIWindow?

    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        if userActivity.activityType == NSUserActivityTypeBrowsingWeb {
            if let incomingURL = userActivity.webpageURL {
                handleIncomingURL(incomingURL)
            }
        }
        return true
    }
    
    func handleIncomingURL(_ url: URL) {
        let components = URLComponents(url: url, resolvingAgainstBaseURL: true)
        if components?.host == "myapp.com" {
            if let queryItems = components?.queryItems {
                var promoCode: String?
                var discount: String?
                
                for item in queryItems {
                    if item.name == "code" {
                        promoCode = item.value
                    } else if item.name == "discount" {
                        discount = item.value
                    }
                }
                
                if let promoCode = promoCode, let discount = discount {
                    applyPromotionToUserAccount(promoCode: promoCode, discount: discount)
                }
            }
        }
    }
    
    func applyPromotionToUserAccount(promoCode: String, discount: String) {
        // Logic to apply promo code and discount to user account
        print("Applying promo code: \(promoCode) with discount: \(discount)%")
    }
}